(()=>{(Drupal=>{Drupal.behaviors.languageToastPositioning={attach(t){if(t!==document||window.languageToastInitialized){return}const a=t.querySelectorAll(".nav-toggle__button.has-toast");a.forEach(t=>{if(t.dataset.toastInitialized)return;t.addEventListener("click",()=>{const a=t.parentElement;const n=a?.nextElementSibling;if(!n||!n.classList.contains("nav-toggle-dropdown--language-toast")){return}Drupal.toastPositioner.positionToast(t,n)});t.dataset.toastInitialized="true"});window.languageToastInitialized=true}}})(Drupal)})();